import{_ as r,o as e,c as o,a0 as t}from"./chunks/framework.jwovEGr5.js";const f=JSON.parse('{"title":"📖 CraftCoreShop 官方說明書","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),l={name:"index.md"};function i(h,a,n,s,d,c){return e(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="📖-craftcoreshop-官方說明書" tabindex="-1">📖 CraftCoreShop 官方說明書 <a class="header-anchor" href="#📖-craftcoreshop-官方說明書" aria-label="Permalink to &quot;📖 CraftCoreShop 官方說明書&quot;">​</a></h1><p>歡迎來到 <strong>CraftCoreShop</strong> 伺服器官方說明書！本指南將協助您快速熟悉本伺服器的箱子商店、領地防護、密碼安全箱，以及 Discord 機器人與網頁儀表板的使用方法。</p><hr><h2 id="🌐-系統三向連動設計" tabindex="-1">🌐 系統三向連動設計 <a class="header-anchor" href="#🌐-系統三向連動設計" aria-label="Permalink to &quot;🌐 系統三向連動設計&quot;">​</a></h2><p>本伺服器採用「遊戲內模組」、「Discord 聊天群組」與「網頁儀表板」三合一的即時互通系統，您的帳號金幣與資料會在這三個平台之間自動同步：</p><ul><li><strong>遊戲伺服器</strong>：進行箱子商店買賣、框選領地、密碼鎖設定與每日任務。</li><li><strong>Discord 機器人</strong>：進行每日簽到、福利抽獎、查看商店狀況與發送快遞。</li><li><strong>網頁儀表板</strong>：在網頁上直觀查看全服富豪排行榜、管理您的領地權限與密碼箱、閱讀實時交易廣播。</li></ul><hr><h2 id="🧭-文件導覽目錄" tabindex="-1">🧭 文件導覽目錄 <a class="header-anchor" href="#🧭-文件導覽目錄" aria-label="Permalink to &quot;🧭 文件導覽目錄&quot;">​</a></h2><p>您可以點選下方連結深入閱讀各單元的詳細教學：</p><h3 id="📦-1-箱子商店系統指南" tabindex="-1">📦 1. 箱子商店系統指南 <a class="header-anchor" href="#📦-1-箱子商店系統指南" aria-label="Permalink to &quot;📦 1. 箱子商店系統指南&quot;">​</a></h3><p>箱子商店是伺服器玩家交易的核心，支援自主擺攤、雙向買賣、預約與評價。</p><ul><li>📖 <a href="./Shop-Creation.html">【第一篇】商店建立與設定</a> — 啟動建立模式、手持物品定價與告示牌發光特效。</li><li>📖 <a href="./Shop-Transaction.html">【第二篇】買家交易與預約</a> — 告示牌右鍵點擊、買賣對話框操作、叮音效提示、缺貨預約訂單與交易評價。</li><li>📖 <a href="./Shop-Management.html">【第三篇】賣家管理與更名</a> — 商店清單瀏覽、告示牌店主管理選單、商店自訂更名與大宗批發模式。</li></ul><h3 id="🛡️-2-領地防護與密碼箱安全指南" tabindex="-1">🛡️ 2. 領地防護與密碼箱安全指南 <a class="header-anchor" href="#🛡️-2-領地防護與密碼箱安全指南" aria-label="Permalink to &quot;🛡️ 2. 領地防護與密碼箱安全指南&quot;">​</a></h3><p>提供對您個人基地、箱子財產的全面安全防護與授權管理。</p><ul><li>📖 <a href="./Claims-Lockboxes.html">安全系統：領地與密碼鎖</a> — 木鋤頭領地框選、區塊防護購置、網頁細部權限管理、安全箱鎖定與網頁密碼箱名冊。</li></ul><h3 id="⚖️-3-經濟與回收系統指南" tabindex="-1">⚖️ 3. 經濟與回收系統指南 <a class="header-anchor" href="#⚖️-3-經濟與回收系統指南" aria-label="Permalink to &quot;⚖️ 3. 經濟與回收系統指南&quot;">​</a></h3><p>伺服器內建虛擬貨幣經濟，提供穩定的基礎回收管道與即時市場趨勢分析。</p><ul><li>📖 <a href="./Economy-Recycle.html">【第四篇】回收與限額機制</a> — 全服首富排行榜與自由市場模式說明。</li><li>📖 <a href="./Market-Analytics.html">【第五篇】市場均價與趨勢</a> — 今日成交均價統計與 7 日物價漲跌看板。</li><li>📖 <a href="./Web-Dashboard.html">【網頁版】網頁儀表板使用與管理</a> — 網頁首頁、任務進度條、個人簽到紀錄、快遞信箱與即時日誌。</li></ul><h3 id="🤖-4-discord-機器人與連動指南" tabindex="-1">🤖 4. Discord 機器人與連動指南 <a class="header-anchor" href="#🤖-4-discord-機器人與連動指南" aria-label="Permalink to &quot;🤖 4. Discord 機器人與連動指南&quot;">​</a></h3><ul><li>📖 <a href="./Discord-Integration.html">機器人：Discord 機器人連動</a> — 帳號雙向綁定、福利控制面板、離線快遞收發信箱與即時成交推播頻道。</li></ul>',20)])])}const u=r(l,[["render",i]]);export{f as __pageData,u as default};
